// @ts-check
import { defineConfig } from 'astro/config';

// GitHub Pages project site: https://dimmonk.github.io/TMV-Web/
// `site` + `base` make Astro emit correct absolute URLs (canonical, OG,
// sitemap) and prefix every built asset path with the repo subpath.
// Sitemap is generated by src/pages/sitemap.xml.ts (no external integration).
export default defineConfig({
  site: 'https://dimmonk.github.io',
  base: '/TMV-Web',
  trailingSlash: 'ignore',
  build: { format: 'directory' },
});
